arguments.command:
$path='C:\Users\Gustavo\.openclaw\openclaw.json';
$json = Get-Content -Raw $path | ConvertFrom-Json;

if (-not $json.agents.defaults.heartbeat) {
  $json.agents.defaults | Add-Member -NotePropertyName heartbeat -NotePropertyValue ([pscustomobject]@{})
}
$json.agents.defaults.heartbeat.every = '45m'
$json.agents.defaults.heartbeat.target = 'last'
$json.agents.defaults.heartbeat.activeHours = [pscustomobject]@{ start = '08:00'; end = '22:30' }

if (-not $json.agents.defaults.subagents) {
  $json.agents.defaults | Add-Member -NotePropertyName subagents -NotePropertyValue ([pscustomobject]@{})
}
$json.agents.defaults.subagents.maxSpawnDepth = 2
$json.agents.defaults.subagents.maxChildrenPerAgent = 3
$json.agents.defaults.subagents.maxConcurrent = 4
$json.agents.defaults.subagents.archiveAfterMinutes = 45
$json.agents.defaults.subagents.runTimeoutSeconds = 900
$json.agents.defaults.subagents.model = 'ollama/qwen3:8b'

if (-not $json.cron) {
  $json | Add-Member -NotePropertyName cron -NotePropertyValue ([pscustomobject]@{})
}
$json.cron.enabled = $true
$json.cron.maxConcurrentRuns = 1
$json.cron.sessionRetention = '12h'
$json.cron.runLog = [pscustomobject]@{ maxBytes = '3mb'; keepLines = 1500 }

$json | ConvertTo-Json -Depth 100 | Set-Content -Path $path -Encoding UTF8;
Get-Content -Raw $path

