arguments.command:
$path='C:\Users\Gustavo\.openclaw\openclaw.json';
$json = Get-Content -Raw $path | ConvertFrom-Json;

$json.agents.defaults.heartbeat = [pscustomobject]@{
  every = '45m'
  target = 'last'
  activeHours = [pscustomobject]@{ start = '08:00'; end = '22:30' }
}

$json.agents.defaults.subagents = [pscustomobject]@{
  maxSpawnDepth = 2
  maxChildrenPerAgent = 3
  maxConcurrent = 4
  archiveAfterMinutes = 45
  runTimeoutSeconds = 900
  model = 'ollama/qwen3:8b'
}

$json.cron = [pscustomobject]@{
  enabled = $true
  maxConcurrentRuns = 1
  sessionRetention = '12h'
  runLog = [pscustomobject]@{ maxBytes = '3mb'; keepLines = 1500 }
}

$json | ConvertTo-Json -Depth 100 | Set-Content -Path $path -Encoding UTF8;
Get-Content -Raw $path

